  static ChemicalElement? getElementBySymbol(String symbol) {
    return _elements.cast<ChemicalElement?>().firstWhere(
      (e) => e?.symbol.toLowerCase() == symbol.toLowerCase(),
      orElse: () => null,
    );
  }

  static List<ChemicalElement> getElementsByCategory(ElementCategory category) {
    return _elements.where((e) => e.category == category).toList();
  }

  static List<ChemicalElement> searchElements(String query) {
    final lowerQuery = query.toLowerCase();
    return _elements.where((e) =>
      e.name.toLowerCase().contains(lowerQuery) ||
      e.symbol.toLowerCase().contains(lowerQuery) ||
      e.atomicNumber.toString() == query
    ).toList();
  }
